#!/usr/bin/env node
// QA Council - Structural Checks: School Builder
// Generated by The Engineer (Agent 3). Validates school builder HTML/JS cross-references.
// Usage: node structural-checks-school.js

var fs = require('fs');
var path = require('path');
var childProcess = require('child_process');

// ============================================================================
// CONFIG
// ============================================================================
var CONFIG = {
  target: 'school',
  basePath: '/sessions/sleepy-gifted-allen/mnt/site/strategic-school',
  htmlFile: 'index.html',
  jsFiles: [
    'js/school.js',
    'js/school-data.js',
    'js/state-config.js'
  ],
  expectedSteps: 12
};

var results = [];
var passed = 0;
var failed = 0;

function assert(condition, testName, details) {
  if (condition) {
    console.log('[PASS] ' + testName);
    passed++;
  } else {
    console.log('[FAIL] ' + testName + (details ? ': ' + details : ''));
    failed++;
  }
  results.push({ test: testName, passed: condition, details: details || '' });
}

// ============================================================================
// TEST 1: Syntax Validation
// ============================================================================
function testSyntax() {
  console.log('\n--- Syntax Validation ---');
  CONFIG.jsFiles.forEach(function(jsFile) {
    var filePath = path.join(CONFIG.basePath, jsFile);
    try {
      if (!fs.existsSync(filePath)) {
        assert(false, 'File exists: ' + jsFile, 'File not found');
        return;
      }
      childProcess.execSync('node --check "' + filePath + '" 2>&1', { encoding: 'utf8' });
      assert(true, 'Syntax: ' + jsFile);
    } catch(e) {
      assert(false, 'Syntax: ' + jsFile, (e.stderr || e.message || '').substring(0, 100));
    }
  });
}

// ============================================================================
// TEST 2: getElementById References
// ============================================================================
function testElementIds() {
  console.log('\n--- Element ID References ---');
  var htmlPath = path.join(CONFIG.basePath, CONFIG.htmlFile);
  if (!fs.existsSync(htmlPath)) {
    assert(false, 'HTML file exists', 'index.html not found');
    return;
  }

  var htmlContent = fs.readFileSync(htmlPath, 'utf8');

  // Extract all IDs from HTML
  var htmlIds = new Set();
  var idRegex = /id=["']([^"']+)["']/g;
  var match;
  while ((match = idRegex.exec(htmlContent)) !== null) {
    htmlIds.add(match[1]);
  }

  // Extract all getElementById calls from JS
  var jsGetElementIds = new Set();
  CONFIG.jsFiles.forEach(function(jsFile) {
    var jsPath = path.join(CONFIG.basePath, jsFile);
    if (!fs.existsSync(jsPath)) return;
    var jsContent = fs.readFileSync(jsPath, 'utf8');
    var getByIdRegex = /getElementById\(['"]([^'"]+)['"]\)/g;
    while ((match = getByIdRegex.exec(jsContent)) !== null) {
      jsGetElementIds.add(match[1]);
    }
  });

  // Dynamic IDs created at runtime
  var dynamicIdPrefixes = ['goal_', 'goalArea', 'strat_', 'action_'];

  var missing = [];
  jsGetElementIds.forEach(function(id) {
    var isDynamic = dynamicIdPrefixes.some(function(prefix) { return id.startsWith(prefix); });
    if (!isDynamic && !htmlIds.has(id)) {
      missing.push(id);
    }
  });

  assert(missing.length === 0, 'All static IDs exist in HTML', missing.length > 0 ? 'Missing: ' + missing.join(', ') : '');
}

// ============================================================================
// TEST 3: onclick/onchange Handler Exports
// ============================================================================
function testOnclickHandlers() {
  console.log('\n--- Onclick Handler Exports ---');
  var htmlPath = path.join(CONFIG.basePath, CONFIG.htmlFile);
  var htmlContent = fs.readFileSync(htmlPath, 'utf8');

  // Extract onclick/onchange function names from HTML
  var handlerRegex = /on(?:click|change)=["'](\w+)\(/g;
  var handlers = new Set();
  var match;
  while ((match = handlerRegex.exec(htmlContent)) !== null) {
    handlers.add(match[1]);
  }

  // Collect all window exports from JS
  var windowExports = new Set();
  CONFIG.jsFiles.forEach(function(jsFile) {
    var jsPath = path.join(CONFIG.basePath, jsFile);
    if (!fs.existsSync(jsPath)) return;
    var jsContent = fs.readFileSync(jsPath, 'utf8');
    var exportRegex = /window\.(\w+)\s*=/g;
    while ((match = exportRegex.exec(jsContent)) !== null) {
      windowExports.add(match[1]);
    }
  });

  var missing = [];
  handlers.forEach(function(handler) {
    if (!windowExports.has(handler)) {
      missing.push(handler);
    }
  });

  assert(missing.length === 0, 'All onclick handlers exported to window', missing.length > 0 ? 'Missing: ' + missing.join(', ') : '');
}

// ============================================================================
// TEST 4: Step Completeness
// ============================================================================
function testStepCompleteness() {
  console.log('\n--- Step Completeness ---');
  var htmlPath = path.join(CONFIG.basePath, CONFIG.htmlFile);
  var htmlContent = fs.readFileSync(htmlPath, 'utf8');

  var allStepsComplete = true;
  for (var i = 1; i <= CONFIG.expectedSteps; i++) {
    // Check HTML step content
    var stepContentRegex = new RegExp('data-step=["\']' + i + '["\']');
    var hasContent = stepContentRegex.test(htmlContent);

    // Check sidebar item
    var sidebarRegex = new RegExp('stepGoto\\(' + i + '\\)');
    var hasSidebar = sidebarRegex.test(htmlContent);

    if (!hasContent || !hasSidebar) {
      allStepsComplete = false;
      assert(false, 'Step ' + i + ' complete', 'Missing ' + (!hasContent ? 'content' : '') + (!hasSidebar ? (hasContent ? '' : ' ') + 'sidebar' : ''));
    } else {
      assert(true, 'Step ' + i + ' complete');
    }
  }
}

// ============================================================================
// TEST 5: Cross-File Variable References (School-Specific)
// ============================================================================
function testCrossFileReferences() {
  console.log('\n--- Cross-File Variable References ---');

  // These databases must be defined in school-data.js or state-config.js
  var criticalRefs = [
    { name: 'GOAL_AREAS_DB', shouldBeIn: 'school-data.js', usedIn: 'school.js' },
    { name: 'ESSA_EVIDENCE_TIERS', shouldBeIn: 'school-data.js', usedIn: 'school.js' },
    { name: 'NAMED_PROGRAMS_DB', shouldBeIn: 'school-data.js', usedIn: 'school.js' },
    { name: 'STATE_ESSA_CONFIG', shouldBeIn: 'state-config.js', usedIn: 'school.js' },
    { name: 'DISTRICT_DATABASE', shouldBeIn: 'school-data.js', usedIn: 'school.js' }
  ];

  criticalRefs.forEach(function(ref) {
    var defPath = path.join(CONFIG.basePath, 'js/' + ref.shouldBeIn);
    if (!fs.existsSync(defPath)) {
      assert(false, 'Cross-ref: ' + ref.name + ' defined', 'File not found: ' + ref.shouldBeIn);
      return;
    }
    var content = fs.readFileSync(defPath, 'utf8');
    var defRegex = new RegExp('var\\s+' + ref.name + '\\s*=|' + ref.name + '\\s*=\\s*{');
    assert(defRegex.test(content), 'Cross-ref: ' + ref.name + ' defined in ' + ref.shouldBeIn);
  });

  // Check that school.js uses these references
  var schoolPath = path.join(CONFIG.basePath, 'js/school.js');
  if (fs.existsSync(schoolPath)) {
    var schoolContent = fs.readFileSync(schoolPath, 'utf8');
    var usageCount = 0;
    criticalRefs.forEach(function(ref) {
      if (schoolContent.includes(ref.name)) {
        usageCount++;
      }
    });
    assert(usageCount >= 4, 'Cross-file references used in school.js', 'Found ' + usageCount + '/5 expected references');
  }
}

// ============================================================================
// TEST 6: Dynamic ID Creation (Goal Modals)
// ============================================================================
function testDynamicIdCreation() {
  console.log('\n--- Dynamic ID Creation ---');
  var schoolPath = path.join(CONFIG.basePath, 'js/school.js');
  if (!fs.existsSync(schoolPath)) {
    assert(false, 'school.js exists', 'File not found');
    return;
  }

  var schoolContent = fs.readFileSync(schoolPath, 'utf8');

  // These IDs are referenced but might be created dynamically via innerHTML
  var expectedDynamicIds = ['goalBuilderModal', 'goalAreaAddModal', 'goalStatement', 'goalNeed', 'goalRootCause', 'goalDate', 'goalMetric', 'goalTarget'];

  var createdDynamically = [];
  expectedDynamicIds.forEach(function(id) {
    // Check if the ID is created via innerHTML or createElement patterns
    var internalHtmlRegex = new RegExp('id["\']?\\s*:\\s*["\']' + id + '["\']|id\\s*=\\s*["\']' + id + '["\']|createElement.*id.*' + id);
    if (internalHtmlRegex.test(schoolContent)) {
      createdDynamically.push(id);
    }
  });

  assert(createdDynamically.length > 0, 'Goal modal IDs created dynamically', 'Found ' + createdDynamically.length + ' dynamic creations');
}

// ============================================================================
// RUN ALL TESTS
// ============================================================================
console.log('\n======================================');
console.log('QA Council: Structural Checks (School)');
console.log('======================================');
console.log('Target: ' + CONFIG.target);
console.log('Base Path: ' + CONFIG.basePath);
console.log('');

testSyntax();
testElementIds();
testOnclickHandlers();
testStepCompleteness();
testCrossFileReferences();
testDynamicIdCreation();

console.log('\n======================================');
console.log('Results: ' + passed + ' passed, ' + failed + ' failed');
console.log('======================================\n');

// Write results to JSON
var outputPath = path.join(path.dirname(process.argv[1]), 'structural-results-school.json');
fs.writeFileSync(outputPath, JSON.stringify({
  target: CONFIG.target,
  timestamp: new Date().toISOString(),
  passed: passed,
  failed: failed,
  total: passed + failed,
  results: results
}, null, 2));

console.log('Results written to: structural-results-school.json');
process.exit(failed > 0 ? 1 : 0);
